import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, NavLink } from 'react-router-dom';

// Import all your pages
import Navbar from './components/Navbar';
import ProtectedRoute from './components/ProtectedRoute';
import SplashPage from './pages/SplashPage';
import HomePage from './pages/HomePage';
import PostPage from './pages/PostPage';
import LoginPage from './pages/LoginPage';
import AboutPage from './pages/AboutPage';
import ContactPage from './pages/ContactPage';
import RegisterPage from './pages/RegisterPage';
import ProfilePage from './pages/ProfilePage';
import CreatePostPage from './pages/CreatePostPage';
import EditPostPage from './pages/EditPostPage';
import AdminPage from './pages/AdminPage';

const App = () => {
  // --- THEME STATE & LOGIC ---
  // Initialize state with localStorage value, or default to 'dark'
  const [theme, setTheme] = useState(() => {
    return localStorage.getItem('theme') || 'dark';
  });

  // Whenever the theme state changes, update the HTML element and localStorage
  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prevTheme => (prevTheme === 'dark' ? 'light' : 'dark'));
  };

  return (
    <Router>
      {/* --- GLOBAL HEADER --- */}
      <header>
        <h1>Gaming Portfolio</h1>
        <nav>
          <ul className="nav-links">
            {/* NavLink automatically adds the class 'active' when the URL matches! */}
            <li><NavLink to="/">Welcome</NavLink></li>
            <li><NavLink to="/home">Home</NavLink></li>
            <li><NavLink to="/about">About</NavLink></li>
            <li><NavLink to="/contact">Contact</NavLink></li>
            <li><NavLink to="/register">Register</NavLink></li>
          </ul>

          <button onClick={toggleTheme} className="toggle-btn">
            {theme === 'dark' ? '☀️ Light Mode' : '🌙 Dark Mode'}
          </button>
        </nav>
      </header>

      {/* --- PAGE ROUTING --- */}
      {/* The Routes component acts like a placeholder. It looks at the URL and renders the matching component here. */}
      <Navbar />
      <Routes>
        {/* Public routes — anyone can visit */}
        <Route path="/" element={<SplashPage />} />
        <Route path="/home" element={<HomePage />} />
        <Route path='/posts/:id' element={<PostPage />} />
        <Route path='/login' element={<LoginPage />} />
        <Route path="/about" element={<AboutPage />} />
        <Route path="/contact" element={<ContactPage />} />
        <Route path="/register" element={<RegisterPage />} />

       {/* Protected routes — must be logged in */}
        <Route path='/profile'
          element={<ProtectedRoute><ProfilePage /></ProtectedRoute>} />
        <Route path='/create-post'
          element={<ProtectedRoute><CreatePostPage /></ProtectedRoute>} />
        <Route path= '/edit-post/:id'
          element={<ProtectedRoute><EditPostPage /></ProtectedRoute>} />
      {/* Admin only — redirects members/guests to home */}
        <Route path='/admin'
          element={<ProtectedRoute role='admin'><AdminPage /></ProtectedRoute>}/>
      </Routes>

      {/* --- GLOBAL FOOTER --- */}
      <footer>
        <p>Contact: example@email.com</p>
        <p>© CAS's Gaming Portfolio</p>
      </footer>
    </Router>
  );
};

export default App;
